// @ts-check
/**
 * @file Build step: read everything under public/ and emit
 * src/assets.generated.js as a plain JS module (base64 bodies).
 *
 * Why: pkg reliably bundles anything reached by a static require(), but its
 * asset-glob config is easy to miss when the entry is a bare .js file. Turning
 * the assets into a required module removes all ambiguity — they become code.
 */

const fs = require('fs');
const path = require('path');

const PUBLIC = path.join(__dirname, '..', 'public');

const OUT = path.join(__dirname, '..', 'src', 'assets.generated.js');

const TYPES = {
    '.html': 'text/html; charset=utf-8',
    '.js': 'application/javascript; charset=utf-8',
    '.css': 'text/css; charset=utf-8',
    '.png': 'image/png',
    '.jpg': 'image/jpeg',
    '.svg': 'image/svg+xml',
    '.ico': 'image/x-icon',
    '.json': 'application/json'
};

/** @type {Record<string, {type:string, b64:string}>} */
const out = {};

/**
 * @param {string} dir
 * @param {string} base
 */
function walk(dir, base) {
    for (const name of fs.readdirSync(dir)) {
        const fp = path.join(dir, name);

        const url = base + '/' + name;

        if (fs.statSync(fp).isDirectory()) {
            walk(fp, url);
        } else {
            out[url] = {
                type: TYPES[path.extname(name)] || 'application/octet-stream',
                b64: fs.readFileSync(fp).toString('base64')
            };
        }
    }
}

walk(PUBLIC, '');

const banner = '// AUTO-GENERATED by scripts/bundle-assets.js — do not edit.\n';

fs.writeFileSync(OUT, banner + 'module.exports = ' + JSON.stringify(out) + ';\n');

console.log(`[bundle-assets] wrote ${Object.keys(out).length} assets to ${path.relative(process.cwd(), OUT)}`);
